import requests

def deny_access(url):
    try:
        response = requests.get(url, timeout=1)
        if response.status_code == 200:
            print(f"Access granted to {url}")
        else:
            print(f"Access denied to {url}")
    except requests.exceptions.RequestException as e:
        print(f"An error occurred: {e}")

